// import { Z_FIXED } from "zlib";

class AttributeEditor {
	constructor(owner, attr) {
		this.owner = owner;		//当前编辑对应的控件
		this.attr = attr;			//当前编辑对应的控件属性
		this.element = null;
		this.value = "";
		this.load();
		// this.setValue(getAttributesValue.call(this, owner, attr.bindControlAttr),false);
	}
	createDom() {}
	setValue(value, args, triggerChange) {
		this.value = value;
		if (triggerChange != false) {
			change(this.owner, this.attr, this.value, args);
		}
		this.changeAttributeView();
	}
	getValue() {
		return this.value;
	}
	load() {
		this.setValue(getAttributesValue.call(this, this.owner, this.attr.bindControlAttr), null, false);
	}
	refreshAttributeView() {
		this.owner.root._pageDesign.loadControlAttributes(this.owner);
	}
	changeAttributeView() {
		//值发生变化时会开启隐藏/显示关联
		if (this.owner._toolRight && (this.attr.hiddenKeyClass != undefined || this.attr.showKeyClass != undefined)) {
			let hideClass = this.attr.hiddenKeyClass || "layui-form-item";
			let showClass = this.attr.showKeyClass || "layui-form-item";
			if (this.attr.showType == 'boolean') {
				/**
				 * boolen==> 
				 *      eg1:hiddenKeyClass = "受影响的class"  
				 *          if(this.v) 显示 else 隐藏
				 *      eg2:hiddenKeyClass = "受影响的class,1"  
				 *          if(this.v=1) 显示 else 隐藏
				 * 
				 *  hiddenKeyClass 里面的值为真的时候显示，为假的时候隐藏
				 */
				let hide = this.value;
				let show = this.value;
				if (hideClass.split(',')[1]) {
					hide = (hideClass.split(',')[1] == this.value);
					hideClass = hideClass.split(',')[0];
				}
				if (showClass.split(',')[1]) {
					show = (showClass.split(',')[1] == this.value);
					showClass = showClass.split(',')[0];
				}				
				if (hide) {
					this.owner._toolRight.find('.' + hideClass).removeClass('ds_item_hidden');
				} else {
					this.owner._toolRight.find('.' + hideClass).addClass('ds_item_hidden');
				}
				if (show) {
					this.owner._toolRight.find('.' + showClass).removeClass('ds_item_hidden');
				} else {
					this.owner._toolRight.find('.' + showClass).addClass('ds_item_hidden');
				}				
			} else if (this.attr.showType == 'rangeSelect') {
				/**
				 * rangeSelect==>用于行政区划
				 *      this.value = [0,5]
				 */
				if (this.value[0]) {
					this.owner._toolRight.find('.' + hideClass).removeClass('ds_item_hidden');
				} else {
					this.owner._toolRight.find('.' + hideClass).addClass('ds_item_hidden');
				}
			}
		}
		if (this.owner._toolRight && (this.attr.hiddenKeyClass != undefined || this.attr.showKeyClass != undefined)) {
			let hideClass = this.attr.hiddenKeyClass || false;
			let showClass = this.attr.showKeyClass || false;
			let val = this.value;
			if (this.attr.showType == 'select') {
				let hide_state = parseInt(val);
				let show_state = parseInt(val);
				let toolRightDom = this.owner._toolRight;
				if (hideClass) {
					_.forEach(hideClass.split(';'), function(item, k) {
						fn(item, false)
					})
				}
				if (showClass) {
					_.forEach(showClass.split(';'), function(item, k) {
						fn(item, true)
					})
				}

				function fn(_class, show) {
					let state = -1;
					if (_class.split(',')[1]) {
						let idx = _class.split(',')[1].indexOf("!");
						if (idx != -1) {
							state = (_class.split(',')[1].slice(idx + 1) != val);
						} else {
							state = (_class.split(',')[1] == val)
						}
						_class = _class.split(',')[0];
					} else {
						state = (eval(val) ? 1 : 0);
					}
					let dom = toolRightDom.find('.' + _class);

					if (state == 0) {
						show ? dom.addClass('ds_item_hidden') : dom.removeClass('ds_item_hidden');
					} else if (state == 1) {
						show ? dom.removeClass('ds_item_hidden') : dom.addClass('ds_item_hidden');
					}
				}
			} else if (this.attr.showType == 'dialog') {
				let hide_state = this.value;
				let show_state = this.value;
				if (hideClass && hideClass.split(',')[1]) {
					hide_state = this.value[hideClass.split(',')[1]];
					hideClass = hideClass.split(',')[0];
				}
				if (showClass && showClass.split(',')[1]) {
					show_state = this.value[showClass.split(',')[1]];
					showClass = showClass.split(',')[0];
				}
				if (hideClass) {
					if (hide_state) {
						this.owner._toolRight.find('.' + hideClass).addClass('ds_item_hidden');
					} else {
						this.owner._toolRight.find('.' + hideClass).removeClass('ds_item_hidden');
					}
				}
				if (showClass) {
					if (show_state) {
						this.owner._toolRight.find('.' + showClass).removeClass('ds_item_hidden');
					} else {
						this.owner._toolRight.find('.' + showClass).addClass('ds_item_hidden');
					}

				}
			}
		}
	}
}

function getAttributesValue(owner, attrName) {
	// let attrSplit=attrName.attrSplit(".");
	let v = "";
	eval("try{\
            v=owner." + attrName + ";\
        }\
        catch(ex){\
            v='';\
        }");
	return v;
}

//修改当前控件绑定的这个属性
function change(owner, attr, value, args) {
	let attrName = attr.bindControlAttr;
	let changeExecFunction = attr.changeExecFunction;
	let arr = attrName.split(".");
	if (arr.length > 1) {
		let temp = owner;
		for (let i = 0; i < arr.length; i++) {
			if (!temp[arr[i]]) {
				temp[arr[i]] = (i >= arr.length - 1) ? null : {};
			}
			temp = temp[arr[i]];
		}
	}
	eval("try{\
            owner." + attrName + "=value;\
            if(changeExecFunction){\
                owner." +
		changeExecFunction +
		"(args);\
            }\
        }\
        catch(ex){\
            console.error('设置属性值['+attrName+']错误:'+ex.message);\
        }"
	);
}

/**
 * 文本属性编辑器
 */
class TextAttributesEditor extends AttributeEditor {
	constructor(owner, attr) {
		super(owner, attr)
	}
	createDom() {
		let _this = this;
		let _type = "type='text'";
		if (this.attr['type']) {
			_type = "type='" + this.attr['type'] + "'";
		}
		let disabled = false;
		let placeholder="请输入"
		if (this.attr.config) {
			disabled = this.attr.config.disabled;
			placeholder=this.attr.config.placeholder||"请输入";
		}
		this.element = $("<input " + _type + " name='" + this.attr.bindControlAttr + "' " + (disabled ? "disabled" : "") +
			" placeholder='"+placeholder+"' autocomplete='off' class='layui-input'>");
		this.element.val(this.value);

		//失去焦点
		this.element.on("blur", evt => {
			this.setValue(_this.element.val(), null);
		});

		//回车事件
		this.element.on("keyup", evt => {
			if (evt.keyCode == 13) {
				this.setValue(_this.element.val(), null);
				return false;
			}
		});
		return this.element;
	}

	setValue(value, args, triggerChange) {
		super.setValue(value, args, triggerChange)
		if (this.element) {
			this.element.val(value);
		}

	}
}

/**
 * 下拉框属性编辑器
 */
class SelectAttributeEditor extends AttributeEditor {
	constructor(owner, attr) {
		super(owner, attr)
	}
	createDom() {

		let _this = this;
		this.element = $("<select lay-filter='attrs_" + this.attr.bindControlAttr + "'  name='" + this.attr.bindControlAttr +
			"'>");
		if (this.attr.dictionary) {
			for (let i = 0; i < this.attr.dictionary.length; i++) {
				if (!this.attr.dictionary[i].hidden) {
					let op = $("<option value='" + this.attr.dictionary[i].value + "'>" + this.attr.dictionary[i].text + "</option>");
					this.element.append(op);
				}
			}
		} else if (this.attr.dictionaryControl) {
			this.owner._root.ControlsForEach(ctrl => {
				if (ctrl.$metadata && ctrl.ctrl_type !== "FlowInfo" && ctrl.ctrl_type !== "TreeInfo" && ctrl.ctrl_type !==
					"AuditInfo") {
					let op = $("<option value='" + ctrl.caption + "'>" + (ctrl.label + " (" + ctrl.caption + ")") + "</option>");
					_this.element.append(op);
				}
			})
		}
		layui.form.on("select(attrs_" + this.attr.bindControlAttr + ")", function(data) {
			_this.setValue(data.value, null);
		});
		this.setValue(getAttributesValue.call(this, this.owner, this.attr.bindControlAttr), null, false);
		return this.element;
	}

	setValue(value, args, triggerChange) {
		super.setValue(value, args, triggerChange);
		if (this.element) {
			this.element.val(this.value);
		}
	}
}

/**
 * 布尔值属性编辑器
 */
class BooleanAttributeEditor extends AttributeEditor {
	constructor(owner, attr) {
		super(owner, attr)
	}
	createDom() {
		this.element = $("<div>");
		let attrCaption = this.attr.bindControlAttr.replace("$", "");
		let input1 = $("<input type='radio' lay-filter='attrs_" + attrCaption + "' name='attr_" + attrCaption +
			"' value='1' title='是'>");
		let input2 = $("<input type='radio' lay-filter='attrs_" + attrCaption + "' name='attr_" + attrCaption +
			"' value='0' title='否'>");
		this.element.append(input1);
		this.element.append(input2);
		let v = this.value === true ? "1" : "0";
		this.element.find("input[value='" + v + "']").prop("checked", true);
		let _this = this;
		layui.form.on("radio(attrs_" + attrCaption + ")", function(data) {
			let v = data.value;
			_this.setValue(v == "1" ? true : false);
		});
		return this.element;
	}

	setValue(value, args, triggerChange) {
		super.setValue(value, args, triggerChange);
		if (this.element) {
			let v = this.value === true ? "1" : "0";
			this.element.find("input[value='" + v + "']").prop("checked", true);
		}
	}
}

/**
 * 子表列项目属性编辑器
 */
class tableColumnAttributeEditor extends AttributeEditor {
	constructor(owner, attr) {
		super(owner, attr)
	}
	createDom() {
		this.element = $("<div>");
		this.updateContext();
		return this.element;
	}
	updateContext() {
		this.element.html("");
		let _this = this;
		for (let i = 0; i < this.value.length; i++) {
			let item = this.value[i]
			let itemEl = $("<div class='layui-row layui-col-space5'/>").appendTo(this.element);
			let one = $("<div class='layui-col-xs4'/>").appendTo(itemEl);
			let two = $("<div class='layui-col-xs4'/>").appendTo(itemEl);
			let three = $("<div class='layui-col-xs4'/>").appendTo(itemEl);
			let text = $("<input type='text' index='" + i + "' placeholder='名称' autocomplete='off' class='layui-input'>").val(
				item.text);
			let width = $("<input type='text' index='" + i + "' placeholder='宽度' autocomplete='off' class='layui-input'>").val(
				item.width);
			one.append(text);
			two.append(width);
			let shang = $("<i title='上移' index='" + i +
				"' class='iconfont icon-shang' style='line-height:40px;font-szie:18px;cursor: pointer;margin-left:3px;' >");
			let xia = $("<i title='下移' index='" + i +
				"'  class='iconfont icon-xia' style='line-height:40px;font-szie:18px;cursor: pointer;margin-left:3px;' >");
			let jia = $("<i title='插入' index='" + i +
				"'  class='iconfont icon-jia' style='line-height:40px;font-szie:18px;cursor: pointer;margin-left:3px;' >");
			let jian = $("<i title='删除' index='" + i +
				"'  class='iconfont icon-jian' style='line-height:40px;font-szie:18px;cursor: pointer;margin-left:3px;' >");
			three.append(shang);
			three.append(xia);
			three.append(jia);
			three.append(jian);

			function widthChange(evt) {
				let target = $(evt.target);
				let index = parseInt(target.attr("index"));
				let val = target.val();
				if (!isNaN(val) && val) {
					this.value[index].width = parseFloat(val);
				} else {
					this.value[index].width = "auto";
				}
				this.setValue(this.value, null, true);
			}

			function textChange(evt) {
				let target = $(evt.target);
				let index = parseInt(target.attr("index"));
				let val = target.val();
				this.value[index].text = val;
				this.setValue(this.value, null, true);
			}
			text.on("blur keyup", evt => {
				if (evt.type == "keyup" && evt.keyCode != 13) {
					return;
				}
				textChange.call(_this, evt);
			});
			width.on("blur keyup", evt => {
				if (evt.type == "keyup" && evt.keyCode != 13) {
					return;
				}
				widthChange.call(_this, evt);
			});
			shang.on("click", evt => {
				let target = $(evt.target);
				let index = parseInt(target.attr("index"));
				if (index - 1 < 0) {
					return;
				}
				let old = this.value[index - 1];
				let current = this.value[index];
				this.value[index - 1] = current;
				this.value[index] = old;
				this.updateContext();
				this.setValue(this.value, index, true);
			});
			xia.on("click", evt => {
				let target = $(evt.target);
				let index = parseInt(target.attr("index"));
				if (index + 1 >= _this.value.length) {
					return;
				}
				let old = _this.value[index + 1];
				let current = _this.value[index];
				_this.value[index + 1] = current;
				_this.value[index] = old;
				_this.updateContext();
				_this.setValue(_this.value, index, true);
			});
			jia.on("click", evt => {
				let target = $(evt.target);
				let index = parseInt(target.attr("index"));
				_this.value.splice(index + 1, 0, {
					text: "列" + (_this.value.length + 1),
					width: ""
				});
				_this.updateContext();
				_this.setValue(_this.value, index, true);
			});
			jian.on("click", evt => {
				let target = $(evt.target);
				let index = parseInt(target.attr("index"));
				_this.value.splice(index, 1);
				_this.updateContext();
				_this.setValue(_this.value, index, true);
			});


		}
	}
	setValue(value, args, triggerChange) {
		super.setValue(value, args, triggerChange);
		if (this.element) {
			let v = this.value === true ? "1" : "0";
			this.element.find("input[value='" + v + "']").prop("checked", true);
		}
	}
}


/**
 * 参数编辑器
 */
class paramAttributeEditor extends tableColumnAttributeEditor {
	updateContext() {
		this.element.html("");
		if (this.value.length == 0) {
			if (this.attr.paramType == 'JSON') {
				this.value.push({
					"": ""
				});
			} else if (this.attr.paramType == 'ARRAY') {
				this.value.push("");
			}
		}
		for (let i = 0; i < this.value.length; i++) {
			let _value = this.value[i]
			this.addContent(_value, i);
		}
	}
	addContent(_value, i) {
		let _this = this;
		let itemEl = $("<div class='layui-row layui-col-space5'/>").appendTo(this.element);
		let $inputOne = '';
		let $inputTwo = '';
		let $inputTool = '';
		let input_key = '';
		let input_value = '';

		if (_this.attr.paramType == 'JSON') {
			let $inputOneP = $("<div class='layui-col-xs5'/>").appendTo(itemEl);
			$inputOne = $("<input type='text' index='" + i + "' placeholder='key' autocomplete='off' class='layui-input'>").val(
				Object.keys(_value) || "");
			$inputOneP.append($inputOne);

			let $inputTwoP = $("<div class='layui-col-xs5'/>").appendTo(itemEl);
			$inputTwo = $("<input type='text' index='" + i + "' placeholder='value' autocomplete='off' class='layui-input'>").val(
				_value[Object.keys(_value)] || "");
			$inputTwoP.append($inputTwo);

			$inputTool = $("<div class='layui-col-xs2'/>").appendTo(itemEl);
		} else if (_this.attr.paramType == 'ARRAY') {
			let $inputOneP = $("<div class='layui-col-xs6'/>").appendTo(itemEl);
			$inputOne = $("<input type='text' index='" + i + "' placeholder='属性名称' autocomplete='off' class='layui-input'>").val(
				_value);
			$inputOneP.append($inputOne);

			let $inputTwoP = $("<div class='layui-col-xs6'/>").appendTo(itemEl);
			$inputTool = $inputTwoP;
		}

		let $add = $("<i title='插入' index='" + i +
			"'  class='iconfont icon-jia' style='line-height:40px;font-szie:18px;cursor: pointer;margin-left:3px;' >");
		let $remove = $("<i title='删除' index='" + i +
			"'  class='iconfont icon-jian' style='line-height:40px;font-szie:18px;cursor: pointer;margin-left:3px;' >");
		$inputTool.append($add);
		$inputTool.append($remove);

		function inputOneChange(evt) {
			let target = $(evt.target);
			let index = parseInt(target.attr("index"));
			input_key = target.val();
			if (_this.attr.paramType == 'JSON') {
				this.value[index] = {};
				this.value[index][input_key] = input_value;
			} else {
				this.value[index] = input_key;
			}
			this.setValue(this.value, null, true);
		}
		$inputOne.on("blur keyup", evt => {
			if (evt.type == "keyup" && evt.keyCode != 13) {
				return;
			}
			inputOneChange.call(_this, evt);
		});

		function inputTwoChange(evt) {
			let target = $(evt.target);
			let index = parseInt(target.attr("index"));
			input_value = target.val();
			this.value[index] = {};
			this.value[index][input_key] = input_value;
			this.setValue(this.value, null, true);
		}
		if ($inputTwo) {
			$inputTwo.on("blur keyup", evt => {
				if (evt.type == "keyup" && evt.keyCode != 13) {
					return;
				}
				inputTwoChange.call(_this, evt);

			});
		}

		$add.on("click", evt => {
			let target = $(evt.target);
			let index = parseInt(target.attr("index"));
			if (_this.attr.paramType == 'JSON') {
				_this.value.splice(index + 1, 0, {
					"": ""
				});
			} else {
				_this.value.splice(index + 1, 0, "");
			}
			_this.updateContext();
			_this.setValue(_this.value, index, true);
		});
		$remove.on("click", evt => {
			let target = $(evt.target);
			let index = parseInt(target.attr("index"));
			_this.value.splice(index, 1);
			_this.updateContext();
			_this.setValue(_this.value, index, true);
		});
	}
}

class dialogAttributesEditor extends AttributeEditor {
	constructor(owner, attr) {
		super(owner, attr)
	}
	createDom() {
		let _this = this;
		let config = this.attr.config;
		this.element = $("<div style='text-align:left;'>");
		let str = config.buttonText;
		let text = $("<a class='ds_button ds_button_auxiliary'>" + str + "</a>");
		this.element.append(text);
		text.on("click", evt => {
			dsf.layer.openDialog({
				title: config.title,
				content: dsf.url.getAbsolutePath(config.url),
				args: _this,
				area: [config.width, config.height],
				btn: _this.buttons(config)
			});
		});
		return this.element;
	}
	buttons(config) {
		let _this = this;
		return [{
			"text": "确定",
			"handler": function(index, layero) {
				let frame = layero.find("iframe");
				//获取dialog content里面的window对象
				let win = frame.get(0).contentWindow;
				//调用那个页面上面定义的getDialogResult方法（返回dialog里面的数据）
				let result = win.getDialogResult();
				if (result === false) {
					return false;
				} else {
					//修改当前控件绑定的这个属性
					_this.setValue(result, null, true);
				}
			}
		}, {
			"text": "取消",
			"handler": function(index, layero) {
				return;
			}
		}]
	}
}

