class fileSizeAttributeEditor extends AttributeEditor {
	constructor(owner, attr) {
		super(owner, attr)
	}
	createDom() {
		this.element = $("<div >");
		let selectDom = $("<div class='layui-input-inline' style='width:43%;'><select lay-filter='attrs_" + this.attr.bindControlAttr +
			"'  name='" + this.attr.bindControlAttr + "' class='selectFileUnit'></div>");
		let inputDom = $(
			"<div class='layui-input-inline'  style='width:43%;'><input type='number' class='fileSize layui-input' name='" +
			this.attr.bindControlAttr + "' placeholder='0' autocomplete='off' min='0'></div>");
		this.element._selectVal = "1", this.element._inputVal = "0";
		this.element.append(inputDom).append(selectDom)
		if (this.attr.dictionary) {
			for (let i = 0; i < this.attr.dictionary.length; i++) {
				let op = $("<option value='" + this.attr.dictionary[i].value + "'>" + this.attr.dictionary[i].text + "</option>");
				this.element.find('select').append(op);
			}
		}
		let _this = this;
		layui.form.on("select(attrs_" + this.attr.bindControlAttr + ")", function(data) {
			_this.element._selectVal = data.value;
			_this.getFileSize(_this)
		});

		_this.element.find("input").on("blur", evt => {
			_this.element._inputVal = _this.element.find("input").val();
			_this.getFileSize(_this)
		});
		//回车事件
		// _this.element.find("input").on("keyup", evt => {
		//     if (evt.keyCode == 13) {
		//         _this.element._inputVal  = _this.element.find("input").val();
		//         _this.getFileSize( _this)
		//     }
		// });
		this.setValue(getAttributesValue.call(this, this.owner, this.attr.bindControlAttr), null, false);
		return this.element;
	}
	setValue(value, args, triggerChange) {
		super.setValue(value, args, triggerChange);
		if (this.element) {
			console.log(this.value)
			this.element.find(".fileSize").val(parseInt(this.value))
			if (this.value.indexOf('M') > -1) {
				this.element.find(".selectFileUnit").val('2')
			} else {
				this.element.find(".selectFileUnit").val('1')
			}
		}
	}
	getFileSize(that) {
		let obj = {
			1: "KB",
			2: "M"
		}
		let element = that.element
		if (!element._inputVal) {
			element._inputVal = '0'
		}
		element._value = element._inputVal + obj[element._selectVal];
		// if (element._selectVal == 1 && this.value.indexOf('M') > -1) {
		//     this.value = element._value = element._inputVal + "M"
		// } else {
		//     element._value = element._inputVal + obj[element._selectVal];
		// }
		that.setValue(element._value, true);
		return element._value
	}
}


/**
 * 范围选择
 */
class rangeSelectAttributeEditor extends AttributeEditor {
	constructor(owner, attr) {
		super(owner, attr)
	}
	createDom() {
		this.element = $("<div>");
		this.updateContext();
		return this.element;
	}
	updateContext(state) {
		this.element.html("");
		let _this = this;
		let itemEl = $("<div class='layui-row layui-col-space5' lay-filter='rangeSelectEditor'/>").appendTo(this.element);
		let selectBoxOne = $("<div class='layui-col-xs5'/>").appendTo(itemEl);
		let toBox = $("<div class='layui-col-xs2' style='height:40px;line-height:40px;text-align:center'/>").appendTo(itemEl);
		toBox.html("至");
		let selectBoxTwo = $("<div class='layui-col-xs5'/>").appendTo(itemEl);
		for (let i = 0; i < 2; i++) {
			let selectDom = $("<select lay-filter='attrs_" + this.attr.bindControlAttr + "_" + i + "'  name='" + this.attr.bindControlAttr +
				"_" + i + "'>");
			if (this.attr.dictionary) {
				for (let j = (i == 0 ? 0 : this.value[0]); j < this.attr.dictionary.length; j++) {
					let selected = (this.attr.dictionary[j].value == this.value[i] ? "selected" : "");
					let op = $("<option value='" + this.attr.dictionary[j].value + "' " + selected + " >" + this.attr.dictionary[j].text +
						"</option>");
					selectDom.append(op);
				}
			}
			let _selectBox = null;
			if (i == 0) {
				_selectBox = selectBoxOne;
			} else {
				_selectBox = selectBoxTwo;
			}
			_selectBox.append(selectDom);
		}

		layui.form.on("select(attrs_" + this.attr.bindControlAttr + "_0)", function(data) {
			_this.value[0] = data.value * 1;
			if (_this.value[1] < _this.value[0]) {
				_this.value[1] = _this.value[0];
			}
			_this.setValue(_this.value, null);
			_this.updateContext(true);
		});
		layui.form.on("select(attrs_" + this.attr.bindControlAttr + "_1)", function(data) {
			_this.value[1] = data.value * 1;
			_this.setValue(_this.value, null);
		});

		if (!state) {
			this.setValue(getAttributesValue.call(this, this.owner, this.attr.bindControlAttr), null, false);
		} else {
			layui.form.render('select', 'attr_form');
		}

	}
	setValue(value, args, triggerChange) {
		super.setValue(value, args, triggerChange);
	}

}

