				let frame = layero.find("iframe");
				let editWin = frame.get(0).contentWindow;
				let currentModel = _this.value.model;
				let newModel = currentModel == "base" ? "super" : "base";
				dsf.layer.confirm("采用" + getModelName(newModel) + "后将覆盖" + getModelName(currentModel) + "的配置信息<br/>确定要继续吗？",
					function() {
						if (newModel == "super") {
							editWin.convertToCode();
						}
						editWin.changeModel(newModel);
						_this.value.model = newModel;
						if (buttons.length > 0) {
							$(".layui-layer-btn1").text(newModel == "base" ? "高级模式" : "基础模式");
						}
					});
				return false;
