//初始化
function initPanel(design, callback) {
  if (design._backgroundImage.url) {
    getImage(design._backgroundImage.url, function(err, image) {
      if (!err) {
        design._backgroundImage.width = image.naturalWidth
        design._backgroundImage.height = image.naturalHeight;
        changePanelSizeForBgImage(design);
        callback && callback()
      } else {
        dsf.layer.message("图片加载失败", false);
      }
    });
  } else {
    let box_w, box_h;
    box_w = 0;
    box_h = 0;
    box_w = parseInt(box_w);
    box_h = parseInt(box_h);
    design._panelSize.scale = 1;
    design._panelSize.width = box_w;
    design._panelSize.height = box_h;
    design._backgroundImage.width = box_w;
    design._backgroundImage.height = box_h;
    callback && callback()
  }
}

function changePanelSizeForBgImage(design) {
  let bg_w = design._backgroundImage.width;
  let bg_h = design._backgroundImage.height;
  if (design.isDesign) {
    let box = $(".edit_range");
    let box_w = box.width();
    let box_h = box.height();
    //计算高度缩放比
    let h_scale = box_h / bg_h;
    let w_scale = box_w / bg_w;
    design._panelSize.width = bg_w;
    design._panelSize.height = bg_h;
    design._panelSize.scale = (h_scale > w_scale) ? w_scale : h_scale;
    let s_w = design.getScaleNum(design._panelSize.width);
    let s_h = design.getScaleNum(design._panelSize.height);
    design._panelSize.move.x = (box_w - s_w) / 2;
    design._panelSize.move.y = (box_h - s_h) / 2;
  } else {
    design._panelSize.width = bg_w;
    design._panelSize.height = bg_h;
    design._panelSize.scale = 1
  }

}

function getImage(src, callback) {
  let image = new Image();
  image.src = dsf.url.getAbsolutePath(src);
  image.onload = function() {
    callback && callback(null, image);
  }
  image.onerror = function() {
    callback && callback(true, image);
  }
}

