/**
 * 将对象放到面板
 */
function createObjectToPanel(data, pos, design) {
  var obj = $.extend(true, {}, data);
  obj.id = obj.id || dsf.uuid();
  obj.left = pos.x;
  obj.top = pos.y;
  obj.angle = obj.angle || 0;
  obj.width = obj.width || 100;
  obj.height = obj.height || 100;
  obj.bgImg = obj.bgImg || {};
  design.$objectList.push(obj);
  obj.sortNum = design.$objectList.length;
  design._viewRender.render();
  return obj;
}

/**
 * 移除对象
 */
function removeObject(obj, design) {
  let index = _.findIndex(design.$objectList, (item) => {
    return item.id == obj.id;
  });
  if (index >= 0) {
    design.$objectList.splice(index, 1);
  }
}

/**
 * 对象选中
 */
function selectedObject(obj, design, evt, vnode) {
  if (evt.which == "1") {
    hideContextMenu(design)
    if (!design._selectedList[obj.id]) {
      selected(obj, design, true);
      // addAction(design);
    }
  } else {
    hideContextMenu(design)
    design._selectedList = {};
    design._selectedList[obj.id] = obj;
    selected(obj, design, true);
    // addAction(design);
  }

}

/**
 * 面板框选
 */
function rangeSelection(rect, design, isClear) {
  if (isClear !== false) {
    design._selectedList = {};
  }
  let list = design.$objectList;
  for (let i = 0; i < list.length; i++) {
    let obj = list[i];
    let pos = getRectInfo(obj);
    let left = Number.MAX_VALUE;
    let right = Number.MIN_VALUE;
    let top = Number.MAX_VALUE;
    let bottom = Number.MIN_VALUE;
    for (let k in pos) {
      if (left > pos[k].x) {
        left = pos[k].x
      }
      if (right < pos[k].x) {
        right = pos[k].x;
      }
      if (top > pos[k].y) {
        top = pos[k].y;
      }
      if (bottom < pos[k].y) {
        bottom = pos[k].y;
      }
    }
    if (left > rect.left && right < (rect.left + rect.width) && top > rect.top && bottom < (rect.top + rect.height)) {
      design._selectedList[obj.id] = list[i];
    }
  }
  let keys = Object.keys(design._selectedList);
  if (keys.length > 0) {
    let rect_1 = getSelectedRect(design);
    design._selectedRect.width = rect_1.width;
    design._selectedRect.height = rect_1.height;
    design._selectedRect.top = rect_1.top;
    design._selectedRect.left = rect_1.left;
    design._selectedRect.angle = rect_1.angle;
    design._selectedRect.show = true;
  } else {
    design._selectedRect.width = 0;
    design._selectedRect.height = 0;
    design._selectedRect.top = 0;
    design._selectedRect.left = 0;
    design._selectedRect.angle = 0;
    design._selectedRect.show = false;
  }
  // design._panelVdom && design._panelVdom.update();
  design._viewRender.render();
}


/**
 * 处理所有被选中
 */
function selected(objectList, design, isClear) {
  let arr = $.type(objectList) == "array" ? objectList : [objectList];
  if (isClear !== false) {
    design._selectedList = {};
  }
  for (let i = 0; i < arr.length; i++) {
    let obj = arr[i];
    design._selectedList[obj.id] = arr[i];
  }
  let rect = getSelectedRect(design);
  design._selectedRect.width = rect.width;
  design._selectedRect.height = rect.height;
  design._selectedRect.top = rect.top;
  design._selectedRect.left = rect.left;
  design._selectedRect.angle = rect.angle;
  design._selectedRect.show = true;
  // design._panelVdom && design._panelVdom.update();
  design._viewRender.render();
}

/**
 * 获取选中框矩形位置信息
 */
function getSelectedRect(design, data) {
  data = data || design._selectedList;
  let keys = Object.keys(data);
  let left = 0,
    width = 0,
    top = 0,
    height = 0,
    angle = 0;
  // 选中一个
  if (keys.length == 1) {
    let obj = design._selectedList[keys[0]];
    left = obj.left;
    width = obj.width;
    top = obj.top;
    height = obj.height;
    angle = obj.angle;
  } else if (keys.length > 1) {
    // 选中多个
    var _left = Number.MAX_VALUE;
    var _right = Number.MIN_VALUE;
    var _top = Number.MAX_VALUE;
    var _bottom = Number.MIN_VALUE;
    for (let i = 0; i < keys.length; i++) {
      let obj = data[keys[i]];
      let pos = getRectInfo(obj);
      for (let k in pos) {
        if (_left > pos[k].x) {
          _left = pos[k].x
        }
        if (_right < pos[k].x) {
          _right = pos[k].x;
        }
        if (_top > pos[k].y) {
          _top = pos[k].y;
        }
        if (_bottom < pos[k].y) {
          _bottom = pos[k].y;
        }
      }
    }
    if (_left == Number.MAX_VALUE) {
      _left = 0
    }
    if (_right == Number.MIN_VALUE) {
      _right = 0
    }
    if (_top == Number.MAX_VALUE) {
      _top = 0
    }
    if (_bottom == Number.MIN_VALUE) {
      _bottom = 0
    }
    left = _left;
    top = _top;
    width = _right - _left;
    height = _bottom - _top;
    angle = 0;
  }
  return {
    left: left,
    top: top,
    width: width,
    height: height,
    angle: angle
  }

}

/**
 * 更新选择框宽高
 */
function updateSelectRect(design, isUpdateDom) {
  let r = getSelectedRect(design);
  design._selectedRect.width = r.width;
  design._selectedRect.height = r.height;
  design._selectedRect.top = r.top;
  design._selectedRect.left = r.left;
  design._selectedRect.angle = r.angle;
  if (isUpdateDom !== false) {
    design._viewRender.render();
  }
}

/**
 * 获取对象上下左右四个边界点
 */
function getRectInfo(obj) {
  let angle = obj.angle;
  let radian = Math.PI * angle / 180;
  let left = obj.left;
  let top = obj.top;
  let right = obj.left + obj.width;
  let bottom = obj.top + obj.height;

  let pos = {
    lt: 0,
    lb: 0,
    rt: 0,
    rb: 0
  }

  let xcenter = (right - left) * (1 / 2) + left;
  let ycenter = (bottom - top) * (1 / 2) + top;

  pos.lt = dsf.Math.getRotatedPiont(left, top, xcenter, ycenter, angle)
  pos.lb = dsf.Math.getRotatedPiont(left, bottom, xcenter, ycenter, angle)
  pos.rt = dsf.Math.getRotatedPiont(right, top, xcenter, ycenter, angle)
  pos.rb = dsf.Math.getRotatedPiont(right, bottom, xcenter, ycenter, angle)
  return pos;
}

/**
 * 隐藏选中框
 */
function hideSelectedRect(design) {
  design._selectedRect.top = 0;
  design._selectedRect.left = 0;
  design._selectedRect.width = 0;
  design._selectedRect.height = 0;
  design._selectedRect.angle = 0;
  design._selectedRect.show = false;
}

/**
 * 隐藏右键菜单
 */
function hideContextMenu(design) {
  design._contextMenuData.top = 0;
  design._contextMenuData.left = 0;
  design._contextMenuData.show = false;
}


var action = [];
/**
 * 记录步骤
 */
function addAction(design) {
  let a = $.extend(true, {}, {
    $objectList: design.$objectList,
    _panelSize: design._panelSize,
    _contextMenuData: initContextMenu(),
    _rangeSelectionRect: initRectData(),
    _selectedRect: initRectData(),
    _selectedList: {}, //design._selectedList,
    _settingStartIndex: design._settingStartIndex,
    _props: initProps()
  });
  action.unshift(a);
  if (action.length > 20) {
    action.pop()
  }
}

function undo(design) {
  let a = action.shift();
  if (a) {
    $.extend(design, a);
    design._viewRender.render();
    // initPanel(design, () => {
    //     design._viewRender.render();
    // });
  }
}

//上传图片
function uploadImage(el, callback) {
  let xsrf = dsf.getCookie("XSRF-TOKEN")
  let url = dsf.url.getWebPath('file/upload');
  let index;
  layui.upload.render({
    elem: el, // 文件选择
    accept: "images",
    multiple: false,
    number: 1,
    headers: { 'X-XSRF-TOKEN': xsrf },
    acceptMime: 'image/*',
    url: url,
    auto: true,
    size: 0,
    before: function() {
      index = dsf.layer.loadding()
    },
    done: function(res) {
      if (dsf.isDef(res.data)) {
        let img = res.data[0];
        if (res.state == 20000) {
          getImage(img.relativePath, function(err, image) {
            callback && callback(err, image, img);
            dsf.layer.close(index);
          });
        }
      }
    },
    error: function(index) {
      dsf.layer.close(index)
    }
  });
}