  //获取组中的子项
  getGroupChild(obj, type) {
    let arr = [];
    let t = 0,
      l = 0;
    let rowSplit = getSplit(obj.height, obj.member.height, obj.rows);
    let colSplit = getSplit(obj.width, obj.member.width, obj.cols);
    for (let i = 0; i < obj.rows; i++) {
      if (i > 0) {
        t += obj.member.height;
        t += rowSplit;
      }
      l = 0;
      for (let n = 0; n < obj.cols; n++) {
        if (n > 0) {
          l += obj.member.width;
          l += colSplit;
        }
        let child = $.extend({}, obj.member);
        child.id = child.id + "-" + i + "-" + n;
        child.angle = 0;
        child.top = t;
        child.left = l;
        arr.push(child);
      }
    }
    return arr;
  }

