  //属性值变化
  propValueChange(key, evt, currObject) {
    let curr = currObject,
      val;
    if (!curr) {
      curr = this._selectedList;
      let keys = Object.keys(curr);
      curr = curr[keys[0]];
    } else {
      curr = currObject;
    }
    if (curr) {
      val = $(evt.currentTarget).val();
      if (key.indexOf("width") >= 0 || key.indexOf("height") >= 0) {
        if (val == "" || isNaN(val)) {
          val = 0;
        }
        if (!val) {
          val = 20;
        } else {
          val = parseInt(val);
        }
      } else if (key.indexOf("top") >= 0 || key.indexOf("left") >= 0) {
        if (val == "" || isNaN(val)) {
          val = 0;
        } else {
          val = parseInt(val);
        }
      } else if (key.indexOf("rowSplit") >= 0 || key.indexOf("colSplit") >= 0) {
        if (val == "" || isNaN(val)) {
          val = 0;
        } else {
          val = parseInt(val);
        }
      }
      let code = [
        "if(obj){",
        "\tobj." + key + "=val;",
        "}"
      ]
      addAction(this);
      let fn = new Function('obj', 'val', code.join("\n"));
      fn(curr, val);
      if (curr.member) {
        if (key.indexOf("width") >= 0 || key.indexOf("height") >= 0) {
          curr.rowSplit = getSplit(curr.height, curr.member.height, curr.rows);
          curr.colSplit = getSplit(curr.width, curr.member.width, curr.cols);
        }
        curr.width = (curr.colSplit * (curr.cols - 1)) + (curr.cols * curr.member.width);
        curr.height = (curr.rowSplit * (curr.rows - 1)) + (curr.rows * curr.member.height);
        curr.member.attrs = curr.attrs;
        setGroupChild(curr)
      }
      updateSelectRect(this, false)
      this._viewRender.render();
    }
    evt.stopPropagation();
    evt.preventDefault();
  }


