  //保存自定义对象
  saveCustomerObject() {
    if (this._customerDialog.obj) {
      let url = dsf.url.getAbsolutePath("/meta/persistData");
      dsf.http.request(url, {
          namespace: "dsfa.seat.seatdesign",
          pageName: "cust",
          data: JSON.stringify({
            "dsfa_seat_seatdesign.name": this._customerDialog.obj.name,
            "dsfa_seat_seatdesign.bgimg": JSON.stringify(this._customerDialog.obj.bgImg),
            "dsfa_seat_seatdesign.source": this._customerDialog.obj.source,
            "_id": this._customerDialog.obj.cid
          })
        }, "POST")
        .done((res) => {
          if (res && res.state == "20000") {
            let obj = {
              cid: res.data["_id"],
              type: "seat",
              isAssist: false,
              text: res.data["dsfa_seat_seatdesign.name"],
              source: res.data["dsfa_seat_seatdesign.source"],
              bgImg: JSON.parse(res.data["dsfa_seat_seatdesign.bgimg"])
            };
            let index = _.findIndex(this._customerList, (item) => {
              return item.cid == res.data["_id"];
            })
            if (index < 0) {
              this._customerList.push(obj)
            } else {
              this._customerList[index] = obj;
            }
            this._viewRender.renderAsync();
          } else {
            dsf.layer.message("保存失败", false);
          }
        })
        .error((res) => {
          dsf.layer.message("保存失败", false);
        }).exec()
    }
  }

