let isDraging = false;

function initToolsDrag(obj, evt) {
  let _this = this;
  let dragElm = $(evt.currentTarget);
  let tools = $(".ds_tools");
  let downMouse = {
    x: evt.pageX,
    y: evt.pageY
  };
  let moveMouse = {
    x: evt.pageX,
    y: evt.pageY
  };
  let margins = {
    top: parseInt(dragElm.css("marginTop"), 10) || 0,
    left: parseInt(dragElm.css("marginLeft"), 10) || 0
  }
  let isStart = false,
    proxy = null,
    dropElm = null;
  // lastPos = { x: moveMouse.x, y: moveMouse.y };
  $(document).on("mousemove.drag", evt => {
    moveMouse.x = evt.pageX;
    moveMouse.y = evt.pageY;
    dropElm = evt.target;
    if (!isStart && (dsf.Math.getDistance(downMouse, moveMouse) > 5)) {
      isDraging = true;
      isStart = true;
      proxy = dragElm.clone();
      proxy.addClass("ds_drag_proxy").appendTo(dragElm.parent());
    } else if (isStart) {
      if (proxy) {
        proxy.css({
          "top": (moveMouse.y - margins.top - tools.offset().top + 5) + "px",
          "left": (moveMouse.x - margins.left - tools.offset().left + 5) + "px",
          "zIndex": "9999"
        });
      }
    }
  });
  $(document).one("mouseup.drag", evt => {
    if (isDraging) {
      try {
        if (isInElmInner("#panel_outer", dropElm)) {
          addAction(_this);
          let data = {}; // $.extend({}, obj); //dragElm.get(0).data;
          let pos = dsf.Math.convertLocalCoordinate("#panel_outer", { x: evt.pageX, y: evt.pageY }, _this._panelSize.scale);
          pos.x = parseInt(pos.x);
          pos.y = parseInt(pos.y);
          data.text = "";
          data.bgImg=obj.bgImg;
          data.type = obj.type;
          data.isAssist = obj.isAssist;
          data.source = obj.source || { "text": obj.text, "value": obj.oid };
          createObjectToPanel(data, pos, _this);
        }
      } catch (ex) {
        dsf.error(ex)
      } finally {
        proxy && proxy.remove();
      }
    }
    $(document).off("mousemove.drag");
  });
  evt.preventDefault();
  evt.stopPropagation();
}

