/**
 * 面板框选
 */
function rangeSelection(rect, design, isClear) {
  if (isClear !== false) {
    design._selectedList = {};
  }
  let list = design.$objectList;
  for (let i = 0; i < list.length; i++) {
    let obj = list[i];
    let pos = getRectInfo(obj);
    let left = Number.MAX_VALUE;
    let right = Number.MIN_VALUE;
    let top = Number.MAX_VALUE;
    let bottom = Number.MIN_VALUE;
    for (let k in pos) {
      if (left > pos[k].x) {
        left = pos[k].x
      }
      if (right < pos[k].x) {
        right = pos[k].x;
      }
      if (top > pos[k].y) {
        top = pos[k].y;
      }
      if (bottom < pos[k].y) {
        bottom = pos[k].y;
      }
    }
    if (left > rect.left && right < (rect.left + rect.width) && top > rect.top && bottom < (rect.top + rect.height)) {
      design._selectedList[obj.id] = list[i];
    }
  }
  let keys = Object.keys(design._selectedList);
  if (keys.length > 0) {
    let rect_1 = getSelectedRect(design);
    design._selectedRect.width = rect_1.width;
    design._selectedRect.height = rect_1.height;
    design._selectedRect.top = rect_1.top;
    design._selectedRect.left = rect_1.left;
    design._selectedRect.angle = rect_1.angle;
    design._selectedRect.show = true;
  } else {
    design._selectedRect.width = 0;
    design._selectedRect.height = 0;
    design._selectedRect.top = 0;
    design._selectedRect.left = 0;
    design._selectedRect.angle = 0;
    design._selectedRect.show = false;
  }
  // design._panelVdom && design._panelVdom.update();
  design._viewRender.render();
}


/**
 * 处理所有被选中
 */
function selected(objectList, design, isClear) {
  let arr = $.type(objectList) == "array" ? objectList : [objectList];
  if (isClear !== false) {
    design._selectedList = {};
  }
  for (let i = 0; i < arr.length; i++) {
    let obj = arr[i];
    design._selectedList[obj.id] = arr[i];
  }
  let rect = getSelectedRect(design);
  design._selectedRect.width = rect.width;
  design._selectedRect.height = rect.height;
  design._selectedRect.top = rect.top;
  design._selectedRect.left = rect.left;
  design._selectedRect.angle = rect.angle;
  design._selectedRect.show = true;
  // design._panelVdom && design._panelVdom.update();
  design._viewRender.render();
}

/**
 * 获取选中框矩形位置信息
 */
function getSelectedRect(design, data) {
  data = data || design._selectedList;
  let keys = Object.keys(data);
  let left = 0,
    width = 0,
    top = 0,
    height = 0,
    angle = 0;
  // 选中一个
  if (keys.length == 1) {
    let obj = design._selectedList[keys[0]];
    left = obj.left;
    width = obj.width;
    top = obj.top;
    height = obj.height;
    angle = obj.angle;
  } else if (keys.length > 1) {
    // 选中多个
    var _left = Number.MAX_VALUE;
    var _right = Number.MIN_VALUE;
    var _top = Number.MAX_VALUE;
    var _bottom = Number.MIN_VALUE;
    for (let i = 0; i < keys.length; i++) {
      let obj = data[keys[i]];
      let pos = getRectInfo(obj);
      for (let k in pos) {
        if (_left > pos[k].x) {
          _left = pos[k].x
        }
        if (_right < pos[k].x) {
          _right = pos[k].x;
        }
        if (_top > pos[k].y) {
          _top = pos[k].y;
        }
        if (_bottom < pos[k].y) {
          _bottom = pos[k].y;
        }
      }
    }
    if (_left == Number.MAX_VALUE) {
      _left = 0
    }
    if (_right == Number.MIN_VALUE) {
      _right = 0
    }
    if (_top == Number.MAX_VALUE) {
      _top = 0
    }
    if (_bottom == Number.MIN_VALUE) {
      _bottom = 0
    }
    left = _left;
    top = _top;
    width = _right - _left;
    height = _bottom - _top;
    angle = 0;
  }
  return {
    left: left,
    top: top,
    width: width,
    height: height,
    angle: angle
  }

}

/**
 * 更新选择框宽高
 */
function updateSelectRect(design, isUpdateDom) {
  let r = getSelectedRect(design);
  design._selectedRect.width = r.width;
  design._selectedRect.height = r.height;
  design._selectedRect.top = r.top;
  design._selectedRect.left = r.left;
  design._selectedRect.angle = r.angle;
  if (isUpdateDom !== false) {
    design._viewRender.render();
  }
}

/**
 * 获取对象上下左右四个边界点
 */
function getRectInfo(obj) {
  let angle = obj.angle;
  let radian = Math.PI * angle / 180;
  let left = obj.left;
  let top = obj.top;
  let right = obj.left + obj.width;
  let bottom = obj.top + obj.height;

  let pos = {
    lt: 0,
    lb: 0,
    rt: 0,
    rb: 0
  }

  let xcenter = (right - left) * (1 / 2) + left;
  let ycenter = (bottom - top) * (1 / 2) + top;

  pos.lt = dsf.Math.getRotatedPiont(left, top, xcenter, ycenter, angle)
  pos.lb = dsf.Math.getRotatedPiont(left, bottom, xcenter, ycenter, angle)
  pos.rt = dsf.Math.getRotatedPiont(right, top, xcenter, ycenter, angle)
  pos.rb = dsf.Math.getRotatedPiont(right, bottom, xcenter, ycenter, angle)
  return pos;
}

