const mainDom = require("../templates/seat.ejs");
import html2canvas from 'html2canvas';

const _STATUS = {
  NORMAL: 0,
  OCCUPY: 1,
  DISABLED: -1,
  LOOK: -2
}
const _STATUSTEXT = {
  "0": "正常",
  "1": "占用",
  "-1": "禁用",
  "-2": "锁定"
}
export class seat extends dsf.Controls.Control {
  constructor() {
    super();
    this.options = null;
    this._templateId = dsf.url.queryString("id");
    this.$headHeight = 62;
    this.$leftWidth = 250;
    this.$objectList = [];  //$objectList存的是有层级关系的所有座位信息, group > child(里面放的是seat)
    this.minSize = [20, 20]
    this._objectMap = [];   //所有座位的信息 isupdate "1"可以入座 "0"不可以入座
    this._objectSortList = [];
    this._contextMenuObject = null;
    this._contextMenuData = {
      top: 0,
      left: 0,
      show: false
    }
    this._backgroundImage = {
      url: "",
      width: 0,
      height: 0,
      success: false
    }
    this._panelSize = {
      width: 0,
      height: 0,
      scale: 1,
      move: {
        x: 0,
        y: 0
      }
    }
    this._viewRender = null;
    this._users = [];
    this._usersMap = {};
    this._seat_user = {};     //需要排座的用户
    this._userInSeat = {};    //已排座的用户
    this._currentFrame = {};
    this._sortWindow = {      //排序弹出框的信息，排序项由dsf_seat_layout.js 里面 frame.sort.items生成
      show: false,
      items: []
    }

    this._STATUS = _STATUS;

    this._compelPanelSize = {
      width: "",
      height: ""
    }

    this.readOnly = false;
    this._isOpenBackendSort = false;  //是否启用后端排座
    this._backendSortIframeUrl = "";   //后端排座弹出面板的url
  }
  
  //返回设计器的配置
  get _designOption(){
    return this.options.designOption? this.options.designOption: {}
  }

  initTemplate() {
    let html = mainDom(this);
    this._viewRender = dsf.vdom({
      template: html,
      data: this,
      inserted: (vnode) => {
        window.setTimeout(() => {
          let q = dsf.queue(true);
          //从服务器获取所有座位的信息
          q.step((def, v) => {
            this.loadTemplate((err, res) => {
              if (err) {
                def.resolve();
              } else {
                if (!res.data) {
                  def.resolve();
                  return;
                }
                let d = res.data;
                this._backgroundImage.url = d["bgsrc"];
                let obj = JSON.parse(d["seatdata"]);
                if (d["seatdata"]) {
                  //$objectList存的是有层级关系的所有座位信息, group > child(里面放的是seat)
                  if (dsf.type(obj) == "array") {
                    this.$objectList = obj;
                  } else {
                    this._compelPanelSize = obj._compelPanelSize || { width: "", height: "" };
                    this.$objectList = obj.$objectList;
                  }
                  
                  //_objectMap 里面为每个座位的信息(无层级)，key为座位的序号(index)
                  this._objectMap = mapObjectList(this);
                  for (let k in this._objectMap) {
                    this.getSeatTextSize(k)
                  }
                }
                def.resolve();
              }
            });
          })
          //加载底图
          q.step((def, v) => {
            initPanel(this, () => {
              def.resolve();
            });
          });
          //调用 dsf_seat_layout.js里面 load对应的配置, 加载每个座位的入座信息，对照座位编号，将其入座
          q.step((def, v) => {
            this.loadData((err, res) => {
              if (!err) {
                if (res) {
                  // this._compelPanelSize = res._compelPanelSize || { width: "", height: "" };
                  _.each(res, (item) => {
                    var s = this._objectMap[item.seatNumber] || {};
                    if (s) {
                      //将item(排座信息对象)里面的sexValue赋值给对应的座位，让座位也有sexValue属性
                      item.sexValue && (this._objectMap[item.seatNumber].sexValue = item.sexValue);
                      
                      //如果此座位有person将其入座
                      if (item.personId) {
                        this.addToSeat(item.seatNumber, { "userId": item.personId, "userName": item.personName })
                      } else {
                        s.state = item.statusValue;
                      }
                      s.isupdate = dsf.isDef(item.isupdate) ? item.isupdate : "1";
                      // s.isupdate = "0";
                    }
                  });
                }
              } else {
                dsf.layer.message(err, false);
              }
              def.resolve();
            });
          });
          //获取后端自动排座iFrame的url地址(如果有的话)
          q.step((def, v) => {
            getBackendSortIframeUrl(this, ()=>{
              def.resolve();
            })
          });
  
          //初始化左侧架构
          q.step((def, v) => {
            loadFrame(this, (err, data) => {
              if (!err) {
                createFrame(this, data);
              }
              def.resolve();
            });
          });
          q.finally(() => {
            this._viewRender.render();
            attachDrag(this);
            //每一个 seat DOM
            let seats = $('.ds_seat_object[type=seat]');
            drag2(this);
            drop(this, seats);
            dsf.UI.renderDelay('checkbox');
            let tipIndex;
            
            //当鼠标移动到 seat DOM上时，弹出user tip(如果有的话)
            $(".edit_range").on("mouseenter", '.ds_seat_object', (evt) => {
              let el = $(evt.currentTarget)
              let id = el.attr("id");
              let seatIndex = el.attr("seat-index");
              if (seatIndex) {
                let user = this._seat_user[seatIndex];
                if (user) {
                  let userName = user.userName;
                  tipIndex = layui.layer.tips(userName, '#' + id, {
                    tips: 1,
                    time: 0
                  });
                }
              }
            });
            $(".edit_range").on("mouseleave", '.ds_seat_object', (evt) => {
              if (tipIndex) {
                layui.layer.close(tipIndex)
              }
            });
          })
          q.exec();
        }, 60)

      },
      updated: (oldVNode, newVNode) => {
        console.log("update")
      }
    });
    return this._viewRender;
  }

  getScaleNum(num) {
    if (dsf.isDef(num) && num != '' && !isNaN(num)) {
      return num * this._panelSize.scale
    }
    return 0;
  }

  getBgPath(bgImgSrc) {
    if (!bgImgSrc) {
      return '';
    } else {
      return dsf.url.getAbsolutePath(bgImgSrc);
    }
  }

  render(el) {
    this._sortWindow.items = this.getFrameSortItems();

    if (!this._viewRender) {
      this.initTemplate();
    }
    let elm = this._viewRender.addToElem(el);
    this.element = $(elm);
    this.renderReady();
    this.resize();
  }

  renderReady() {}


  stopPropagation(evt) {
    evt.stopPropagation();
  }

  addToSeat(seatId, user) {
    if (user) {
      let uid = user.id || user.userId;
      let uname = user.name || user.userName;
      this._seat_user[seatId] = { 'userId': uid, 'userName': uname };
      let s = this._objectMap[seatId] || {};
      s.state = _STATUS.OCCUPY;
    } else {
      delete this._seat_user[seatId];
      let s = this._objectMap[seatId] || {};
      s.state = _STATUS.NORMAL;
    }
    this._userInSeat = {};
    for (let k in this._seat_user) {
      let u = this._seat_user[k];
      this._userInSeat[u.userId] = 1;
    }
  }

  getSeatUser(index) {
    return this._seat_user[index];
  }

  //获取座位状态
  getSeatState(index) {
    if (dsf.isDef(index)) {
      let seat = this._objectMap[index];
      if (this._seat_user[index] && this._seat_user[index].userId) {
        return _STATUS.OCCUPY;
      }
      if (dsf.isDef(seat.state)) {
        return seat.state;
      } else {
        return _STATUS.NORMAL;
      }
    } else {
      return _STATUS.NORMAL;
    }
  }

  showUserName(index) {
    let fontWidth = 20 * 3;
    let s_u = this.getSeatUser(index);
    if (s_u) {
      let s = this._objectMap[index];
      // this.getSeatSize(index);
      let w = this.getScaleNum(s.textWidth) * 0.8;
      if (fontWidth > w) {
        let str = s_u.userName.substr(0, 1);
        return str
      } else {
        let str = s_u.userName;
        return str;
      }
    }
    return "";
  }

  getSeatTextSize(index) {
    let seat = this._objectMap[index];
    if (seat) {
      let x = seat.left;
      let y = seat.top;
      let w = seat.width;
      let h = seat.height;

      let a = seat.parent ? seat.parent.angle : seat.angle;
      let cx = (x + w) / 2;
      let cy = (y + h) / 2;
      let lt = dsf.Math.getRotatedPiont(x, y, cx, cy, a);
      let rt = dsf.Math.getRotatedPiont(x + w, y, cx, cy, a);

      let w_a = Math.ceil(dsf.Math.r2a(dsf.Math.getRadina(lt, rt)));
      let lb = dsf.Math.getRotatedPiont(x, y + h, cx, cy, a);
      let h_a = Math.ceil(dsf.Math.r2a(dsf.Math.getRadina(lt, lb)));

      let w_a_m = getHorizontalAngle(w_a);
      let h_a_m = getHorizontalAngle(h_a);
      let width = seat.width;
      let height = seat.height;
      if (w_a_m < h_a_m) {
        seat.textWidth = width;
        seat.textHeight = height
      } else if (w_a_m > h_a_m) {
        seat.textWidth = height;
        seat.textHeight = width
      } else {
        if (height > width) {
          seat.textWidth = width;
          seat.textHeight = height;
        } else {
          seat.textWidth = height;
          seat.textHeight = width;
        }
      }

    }
  }

  getFrameTitle() {
    let frame = getFrameOption(this)
    frame = frame || {};
    return frame.title || ""
  }

  //放回 dsf_seat_layout.js里面 frame.sort.items(排序配置)
  getFrameSortItems() {
    let frame = getFrameOption(this)
    frame = frame || {};
    if (frame.sort) {
      return frame.sort.items || [];
    }
    return [];
  }
  
  //加载所有座位的信息
  loadTemplate(callback) {
    let id = this._templateId;
    // if (id) {
    //     dsf.http.request(dsf.UrlSetting.form_load, {
    //         "id": id,
    //         "data": JSON.stringify({ "_id": id }),
    //         "pageName": "save",
    //         "namespace": "dsfa.seat.seatdesign"
    //     }, "GET").done(function(res) {
    //         callback && callback(null, res.data)
    //     }).error(function() {
    //         callback && callback(true, null)
    //     }).exec();
    // } else {
    //     callback && callback()
    // }
    if (id) {
      let url = dsf.url.getWebPath("dsfa/seat/designContent/findByRmId");
      dsf.http.request(url, {
        "rmId": id
      }, "GET").done(function(res) {
        callback && callback(null, res)
      }).error(function() {
        callback && callback(true, null)
      }).exec();
    } else {
      callback && callback()
    }
  }

  loadData(callback) {
    let opts = this.options;
    let load = opts.load;
    //返回 dsf_seat_layout.js里面 load对应的url
    let url = getLoadUrl(this);
    if (url) {
      let params = {};
      if (dsf.isDef(load.params)) {
        if (dsf.type(load.params) == "function") {
          params = load.params.call(this);
        }
      }
      url = dsf.url.getAbsolutePath(url)
      dsf.http.request(url, params, 'GET')
        .done((res) => {
          if (res && res.success && res.state == "20000") {
            callback && callback(null, res.data)
          } else if (res && res.state != "20000") {
            callback && callback(res.message, null);
          } else {
            callback && callback("加载数据失败", null);
          }
        })
        .error(() => {
          callback && callback("加载数据失败", null);
        })
        .always(() => {}).exec();

    } else {
      callback && callback()
    }
  }

  save(data, callback) {
    let opts = this.options;
    let save = opts.save;
    let url = getSaveUrl(this);
    if (url) {
      data = dsf.type(data) == "array" ? data : [data];
      let params = data;
      if (dsf.isDef(save.params)) {
        if (dsf.type(save.params) == "function") {
          params = save.params.call(this, data);
        }
      }
      let dindex = dsf.layer.loadding();
      let erroeMsg = "保存失败"
      url = dsf.url.getAbsolutePath(url)
      dsf.http.request(url, params, 'POST')
        .done((res) => {
          if (res && res.success && res.state == "20000") {
            callback && callback()
          } else if (res && res.state != "20000") {
            dsf.layer.message(res.message, false);
          } else {
            dsf.layer.message(erroeMsg, false);
          }
        })
        .error(() => {
          dsf.layer.message(erroeMsg, false);
        })
        .always(() => {
          dsf.layer.close(dindex);
        }).exec();
    }
  }

  //缩放
  scaleHandler(evt) {
    if (evt.ctrlKey) {
      let delta = evt.wheelDelta < 0 ? true : false;
      //获取鼠标在panel中的位置
      let pos = dsf.Math.convertLocalCoordinate('#panel_outer', {
        x: evt.pageX,
        y: evt.pageY
      });
      //获取当前的实际宽度
      let w = this._backgroundImage.width * this._panelSize.scale;
      let h = this._backgroundImage.height * this._panelSize.scale;
      //获取鼠标位置和宽度高度的比例值
      let rw = pos.x / w;
      let rh = pos.y / h;
      let s = this._panelSize.scale;
      let newS = s;
      //向下滚动，缩小
      if (delta) {
        newS -= 0.1
      } else {
        newS += 0.1
      }
      newS = Math.round(newS * Math.pow(10, 1)) / Math.pow(10, 1);
      if (newS >= 0.1) {
        this._panelSize.scale = newS;
        let panel = $("#panel_outer");
        let sw = this._backgroundImage.width * newS;
        let sh = this._backgroundImage.height * newS;
        let l = panel.position().left + pos.x - (sw * rw);
        let t = panel.position().top + pos.y - (sh * rh);
        this._panelSize.move.x = l;
        this._panelSize.move.y = t;
        this._viewRender.renderAsync();
      }
      evt.preventDefault();
      evt.stopPropagation();
    }

  }

  //平移
  panelTranslationHandler(evt) {
    if (!evt.ctrlKey && evt.which == "1") {
      return;
    }
    let _this = this;
    let isDown = true;
    let pos = dsf.Math.convertLocalCoordinate('#panel_outer', { x: evt.pageX, y: evt.pageY }, 1);
    let downPosX = pos.x;
    let downPosY = pos.y;
    $(document).on("mousemove.translation", panelmoveHandler.bind(this));
    $(document).one("mouseup.translation", panelendHandler.bind(this));

    function panelmoveHandler(evt) {
      if (!evt.ctrlKey || !isDown) {
        return;
      }
      let pos = dsf.Math.convertLocalCoordinate('#panel_outer', { x: evt.pageX, y: evt.pageY }, 1);
      let dpos = { x: downPosX, y: downPosY }
      let moveX = (pos.x - dpos.x);
      let moveY = (pos.y - dpos.y);
      // console.log(moveX)
      let scrollleft = this._panelSize.move.x + moveX;
      let scrolltop = this._panelSize.move.y + moveY;
      this._panelSize.move.x = scrollleft;
      this._panelSize.move.y = scrolltop;
      this._viewRender.renderAsync();
    }

    function panelendHandler(evt) {
      isDown = false;
      $(document).off("mousemove.translation");
      evt.preventDefault();
      evt.stopPropagation();
    }
  }

  //复位
  resetMove() {
    this._panelSize.move.x = 0;
    this._panelSize.move.y = 0;
    initPanel(this, () => {
      this._viewRender.renderAsync();
    });
  }

  contextMenuObjectHandler(obj, evt) {
    if (this.isSeatUpdate(obj)) {
      let localPos = dsf.Math.convertLocalCoordinate('#panel_outer', { x: evt.pageX, y: evt.pageY }, this._panelSize.scale);
      this._contextMenuObject = obj;
      this._contextMenuData.show = true;
      this._contextMenuData.left = localPos.x;
      this._contextMenuData.top = localPos.y;
      this._viewRender.render();
    }
    evt.preventDefault();
    evt.stopPropagation();
  }

  panelMouseDownHandler(evt) {
    this._contextMenuData.show = false;
    this._viewRender.render();
    evt.preventDefault();
    // evt.stopPropagation();
  }

  //变更状态
  stateChange(item, state, evt) {
    if (item.state == 1) {
      dsf.layer.message("请先清除位置上的用户", false);
    } else {
      if (item.state == state) {
        item.state = 0;
      } else {
        item.state = state;
      }
    }
    this._contextMenuData.show = false;
    this._viewRender.render();
    // let d = getSaveData(this, item.index);
    // this.save([d]);
    if (evt) {
      evt.preventDefault();
      evt.stopPropagation();
    }
  }

  //删除座位中的用户
  deleteSeatUser(item, isUtilize, evt) {
    let user = this._seat_user[item.index];
    if (user) {
      this.addToSeat(item.index, null);
    }
    this._contextMenuData.show = false;
    if (isUtilize) {
      this.emptySeatUtilize(item.index);
    }
    this.updateView();
    if (evt) {
      evt.preventDefault();
      evt.stopPropagation();
    }
  }

  //左侧菜单点击排序
  openSort() {
    this._sortWindow.show = true;
    let frame = getFrameOption(this);
    let sort = frame.sort;
    // this._sortWindow.items = sort.items || [];
    this._viewRender.render();
    let _this = this;
    let content = $("#sortwindow");
    dsf.layer.openHTMLView(content, {
      title: "人员排序",
      offset: "100px",
      area: sort.size || ["400px", "300px"],
      btn: ["确定", "取消"],
      yes: function(index, layero) {
        let selects = layero.find("select");
        //把所有select最后的排序条件赋予_this._sortWindow
        selects.each((i, el) => {
          let s = $(el).val()
          _this._sortWindow.items[i].selectedValue = s;
        });
        dsf.layer.close(index)
        let q = dsf.queue(true);
        q.step((def, v) => {
          //初始化左侧架构, 清空 _this._users
          _this._currentFrame.clear(_this);
          loadFrame(_this, (err, data) => {
            if (!err) {
              createFrame(_this, data);
            }
            def.resolve();
          });
        })
        q.step((def, v) => {
          attachDrag(_this);
          drag2(_this);
          def.resolve();
        })
        q.finally(() => {
          _this._viewRender.render();
        })
        q.exec();
      },
      end: function() {
        _this._sortWindow.show = false;
        _this._viewRender.render();
      },
      success: function() {
        dsf.UI.renderDelay("select");
      }
    });

  }


  //自动排座
  autoSeat() {
    const _this = this;
    let sortOption;
    //如果启用后端排序
    if (_this._isOpenBackendSort){
      sortOption = getAutoSortOption(_this);
      sortOption.isPopConfirm? judgeConfirm(): openIframe();
    }
    else {
      judgeConfirm();
    }
    
    function judgeConfirm() {
      let keys = Object.keys(_this._seat_user);
      if (keys.length > 0) {
        dsf.layer.confirm("该操作会清除当前所有已排人员重新排位，是否要继续?", () => {
          _this._isOpenBackendSort? openIframe(): reset.call(_this);
        })
      } else {
        _this._isOpenBackendSort? openIframe(): reset.call(_this);
      }
    }

    function reset() {
      let map = [];
      for (let k in this._seat_user) {
        let s = this._objectMap[k];
        if (this.isSeatUpdate(s)) {
          this.addToSeat(k, null);
          map[k] = null;
        }
      }
      let users = this._users.sort((v1, v2) => {
        return v1.sortNum < v2.sortNum ? -1 : 1
      });
      //获取当前用户可以操作的第一个座位
      let firstIndex = this.getUpdateFirstSeat();
      if (dsf.isDef(firstIndex)) {
        let r = getBatchSeat(this, users, firstIndex);
        for (let i = 0; i < r.seats.length; i++) {
          let s = r.seats[i];
          let u = users[i];
          if (u && s) {
            this.addToSeat(s.index, { "userId": u.id, "userName": u.name });
          }
        }
        let data = []
        for (let k in this._seat_user) {
          delete map[k];
          data.push(getSaveData(this, k));
        }
        for (let k in map) {
          data.push(getSaveData(this, k));
        }
        // this.save(data);
        this.updateView();
      }

    }
    
    function openIframe() {
      dsf.layer.openDialog({
        title: sortOption.title,
        area: sortOption.size,
        content: _this._backendSortIframeUrl,
        end(){
          location.reload();
        }
      })
    }
  }

  isAllChecked() {
    let r = true;
    _.each(this._autoSeatUsers, (u) => {
      if (!u.checked) {
        r = false;
      }
    });
    return r;
  }

  getSortAttachItems() {
    let frame = getFrameOption(this);
    let sort = frame.sort;
    return sort.items || [];
  }

  //左侧列表项上移/下移时触发
  userSort(user, type) {
    let index = _.findIndex(this._users, (u) => {
      return u.id == user.id;
    });
    let newindex = null;
    if (type == "up") {
      newindex = index - 1;
      newindex < 0 && (newindex = null)
    } else {
      newindex = index + 1;
      newindex > this._users.length - 1 && (newindex = null);
    }
    if (dsf.isDef(newindex)) {
      let targetUser = this._users[newindex];
      let currentUser = this._users[index];
      this._users[index] = targetUser;
      this._users[newindex] = currentUser;
      _.each(this._users, (u, i) => {
        u.sortNum = i + 1;
      })
      this._users = this._users.sort((v1, v2) => {
        if (v1.sortNum < v2.sortNum) {
          return -1;
        }
        return 1;
      })
      this._viewRender.render();
    }
  }

  clearSeat() {
    dsf.layer.confirm("该操作将清除当前已排座的信息,是否要继续?", () => {
      let posData = [];
      for (let k in this._seat_user) {
        //s为每个座位的信息
        let s = this._objectMap[k];
        //如果此座位可以入座
        if (this.isSeatUpdate(s)) {
          this.addToSeat(k, null);
          posData.push(getSaveData(this, k));
        }
      }
      if (posData && posData.length) {
        // this.save(posData);
        this.updateView();
      }
    });
  }

  updateView() {
    this._viewRender.render();
    this._currentFrame.diff();
    drag2(this);
  }

  saveSeat() {
    let data = [];
    for (let i = 0; i < this._objectSortList.length; i++) {
      let s = this._objectSortList[i];
      let d = getSaveData(this, s.index);
      d.text = s ? s.text : "";
      data.push(d);
    }
    this.save(data, function() {
      dsf.layer.message("保存成功", true);
    });
  }

  getFrameOption() {
    return getFrameOption(this)
  }

  //空位利用
  emptySeatUtilize(startIndex, endIndex) {
    let start, end;
    start = startIndex;
    end = endIndex;
    _.each(this._objectSortList, (s, i) => {
      if (dsf.isDef(s) && dsf.isDef(s.index) && this.isSeatUpdate(s)) {
        let u = this._seat_user[s.index];
        if (dsf.isDef(u)) {
          dsf.isUnDef(start) ? (start = s.index) : (end = s.index);
        }
      }
    });
    if (dsf.isUnDef(end)) {
      end = start;
    }
    if (start > end) {
      var temp = start;
      start = end;
      end = temp;
    }
    let firstEmpty, users = [];
    //查找第一个空位置和将空位后的用户添加到users数组
    for (let i = start; i <= end; i++) {
      let s = this._objectMap[i];
      if (s && dsf.isDef(s.index)) {
        let u = this._seat_user[s.index];
        if (!firstEmpty) {
          let state = dsf.isDef(s.state) ? s.state : _STATUS.NORMAL;
          if (!u && state == _STATUS.NORMAL) {
            firstEmpty = s;
          }
        } else {
          u && users.push(u);
          if (s.state != _STATUS.LOOK && s.state != _STATUS.DISABLED) {
            this.addToSeat(s.index, null);
          }
        }

      }
    }
    if (firstEmpty) {
      let r = getBatchSeat(this, users, firstEmpty.index);
      coverageUserInSeat(this, users, firstEmpty.index, r, []);
      this.updateView()
    }
  }

  //导出图片
  exportImage(callback) {
    let index = dsf.layer.loadding()
    let el = $("#panel_outer").get(0);
    html2canvas(el, {
      useCORS: true,
      allowTaint: false,
      width: this.getScaleNum(this._panelSize.width),
      height: this.getScaleNum(this._panelSize.height),
      scale: 1
    }).then((canvas) => {
      var url = canvas.toDataURL(); //图片地址
      $("#exportLink").attr("href", url);
      window.setTimeout(function() {
        dsf.layer.close(index)
        //判断是否为IE10+
        window.navigator.msSaveBlob? dsf.IE10.download(url, '排座.png'): document.getElementById("exportLink").click();
      }, 500)
      callback && callback(url);
    });
  }
  
  //在ds-for 里面为每个座位设置样式
  getItemCss(item, backgroundObject) {
    let css = {
      'transform': 'rotate(' + item.angle + 'deg)',
      'top': this.getScaleNum(item.top),
      'left': this.getScaleNum(item.left),
      'width': this.getScaleNum(item.width),
      'height': this.getScaleNum(item.height),
      'line-height': this.getScaleNum(item.height)
    }
    if (dsf.isDef(backgroundObject)) {
      let bgImg = backgroundObject.bgImg;
      let state = this.getSeatState(item.index);
      css['background-image'] = 'url(' + this.getBgPath(bgImg[state]) + ')';
    }
    if (dsf.isDef(item.isupdate) && item.type == "seat") {
      css['opacity'] = this.isSeatUpdate(item) ? "1" : "0.6";
    }
    return css
  }

  isSeatUpdate(seat) {
    if (seat) {
      return seat.isupdate != "0";
    }
    return false;
  }

  //获取可以操作的第一个座位序号
  getUpdateFirstSeat() {
    //获取当前用户可以操作的第一个座位
    let firstIndex;
    for (let i = 0; i < this._objectSortList.length; i++) {
      let s = this._objectSortList[i];
      if (this.isSeatUpdate(s)) {
        firstIndex = s.index;
        break;
      }
    }
    return firstIndex;
  }
}



