//将objectList映射成对象
function mapObjectList(seat) {
  let map = {};
  let c;
  let list = seat.$objectList.slice(0);
  seat._objectSortList = [];
  while (c = list.shift()) {
    if (c.type == "seat") {
      dsf.isDef(c.index) && (map[c.index] = c);
      seat._objectSortList.push(c)
    } else if (c.type == "group") {
      _.each(c.child, (item) => {
        if (dsf.isDef(item.index)) {
          item.attrs = c.attrs || {};
          map[item.index] = item;
          Object.defineProperty(map[item.index], "parent", {
            enumerable: false,
            configurable: false,
            writable: false,
            value: c
          });
        }
        seat._objectSortList.push(item);
      });
    }
  }
  // dsf.time("排序")
  seat._objectSortList = seat._objectSortList.sort((v1, v2) => {
    if (dsf.isDef(v1.index) && dsf.isUnDef(v2.index)) {
      return -1;
    }
    if (dsf.isUnDef(v1.index) && dsf.isDef(v2.index)) {
      return 1;
    }
    let i1 = parseInt(v1.index);
    let i2 = parseInt(v2.index);
    return i1 < i2 ? -1 : 1;
  });
  // dsf.timeEnd("排序")
  return map;
}

//获取座位中可用的座位
function getBatchSeat(seat, users, sindex) {
  users = dsf.type(users) == "array" ? users : [users];
  let seats = [],
    hasUserSeats = [];
  let cur_s = seat._objectMap[sindex];
  if (cur_s) {
    //获取与当前用户可以匹配的座位
    let index = _.findIndex(seat._objectSortList, (s) => {
      return s.index == sindex;
    });
    let userNum = users.length;
    while (userNum && index < seat._objectSortList.length) {
      var s = seat._objectSortList[index];
      if (s && s.index && seat.isSeatUpdate(s)) {
        s.state = s.state || _STATUS.NORMAL;
        if (s.state == _STATUS.NORMAL || s.state == _STATUS.OCCUPY) {
          seats.push(s);
          userNum--;
        }
        if (s.state == _STATUS.OCCUPY) {
          let u;
          if (u = seat._seat_user[s.index]) {
            hasUserSeats.push({
              seatIndex: s.index,
              user: {
                id: u.userId,
                name: u.userName
              }
            });
          }

        }
      }
      index++;
    }
  }
  return {
    seats: seats,
    hasUserSeats: hasUserSeats
  }
}

//批量自动排座
function addToSeatBatch(seat, users, index, action) {
  let result = getBatchSeat(seat, users, index);
  let postData = [];
  action = action || 0;
  //action=0进行询问操作
  if (action == 0) {
    if (result.hasUserSeats.length) {
      dsf.layer.openHTMLView(
        '<div style="padding:10px">\
                   位置上已经存在其他人员,您希望如何处理？\
                </div>', {
          id: "seatConfirm",
          area: ['400px', '200px'],
          btn: ['覆盖', '插入', '取消'],
          yes: function(index) {
            coverageUserInSeat(seat, users, index, result, postData);
            com();
            dsf.layer.close(index)
          },
          btn2: function(index) {
            insertUserInSeat(seat, users, index, result, postData);
            com();
            dsf.layer.close(index)
          }
        }
      );
    } else {
      coverageUserInSeat(seat, users, index, result, postData);
      com();
    }
  }
  //action=1直接进行覆盖操作
  else if (action == 1) {
    coverageUserInSeat(seat, users, index, result, postData);
    com();
  }


  function com() {
    // seat.save(postData);
    seat.updateView();
  }
}

function coverageUserInSeat(seat, users, index, checkResult, postData) {
  _.each(checkResult.seats, (s, i) => {
    let u = users[i];
    if (('id' in u) && ('name' in u)) {
      u = {
        "userId": u.id,
        "userName": u.name
      }
    }
    if (dsf.isDef(s.index) && s.index != "") {
      seat.addToSeat(s.index, u);
      postData.push(getSaveData(seat, s.index));
    }
  });
}
//插入用户，当前用户座位顺延处理
function insertUserInSeat(seat, users, index, checkResult, postData) {
  let r = checkResult;
  let lastSeatIndex = null;
  _.each(r.seats, (s, i) => {
    let u = users[i];
    if (('id' in u) && ('name' in u)) {
      u = {
        "userId": u.id,
        "userName": u.name
      }
    }
    if (dsf.isDef(s.index) && s.index != "") {
      seat.addToSeat(s.index, u);
      postData.push(getSaveData(seat, s.index));
      if (i == checkResult.seats.length - 1) {
        lastSeatIndex = s.index;
      }
    }
  });
  if (r && r.hasUserSeats && r.hasUserSeats.length) {
    let users1 = _.map(r.hasUserSeats, (s) => {
      return s.user;
    });
    index = _.findIndex(seat._objectSortList, (s) => {
      return s.index == lastSeatIndex;
    });
    let next = seat._objectSortList[index + 1];
    if (next) {
      checkResult = getBatchSeat(seat, users1, next.index);
      insertUserInSeat(seat, users1, next.index, checkResult, postData);
    }
  }
}

//获取保存数据的结构
function getSaveData(seat, index) {
  let data = {};
  let user = seat._seat_user[index];
  let s = seat._objectMap[index];
  data.user = user || { "userName": "", "userId": "" };
  data.seatId = index;
  data.seatText = s ? s.text : "";
  data.seatAttrs = s.attrs;
  data.seatState = {
    text: _STATUSTEXT[_STATUS.NORMAL],
    value: _STATUS.NORMAL
  }
  if (s) {
    let state = s.state || _STATUS.NORMAL;
    //如果有关于设计器额外上传图片的配置
    if (seat._designOption.extraUpImgBox){
      for (let op of seat._designOption.extraUpImgBox){
        _STATUSTEXT[op.key] || (_STATUSTEXT[op.key] = op.value)
      }
    }
    data.seatState = {
      text: _STATUSTEXT[state],
      value: state
    }
  }
  return data;

}

function getHorizontalAngle(angle) {
  let m;
  //第一象限
  if (angle > 270 && angle <= 360) {
    m = Math.abs(360 - angle);
  }
  //第二象限
  else if (angle > 180 && angle <= 270) {
    m = Math.abs(180 - angle);
  }
  //第三象限
  else if (angle > 90 && angle <= 180) {
    m = Math.abs(180 - angle);
  }
  //第四象限 
  else if (angle >= 0 && angle <= 90) {
    m = Math.abs(0 - angle);
  }
  return m;
}

