//加载左侧列表数据
function loadFrame(seat, callback) {
  //获取 dsf_seat_layout.js里面 frame对应的url
  let url = getFrameUrl(seat, seat);
  if (url) {
    url = dsf.url.getAbsolutePath(url);
    let params = {};
    let frame = getFrameOption(seat);
    if (dsf.isDef(frame.params)) {
      params = frame.params();
    }
    let orders = null;
    if (seat._sortWindow.items && seat._sortWindow.items.length) {
      orders = [];
      _.each(seat._sortWindow.items, (item) => {
        if (item.selectedValue) {
          let obj = {
            "field": item.field,
            "order": item.selectedValue
          }
          orders.push(obj);
        }
      });
      if (orders.length) {
        params.orders = JSON.stringify(orders)
      }
    }
    dsf.http.request(url, params, 'GET')
      .done((res) => {
        if (res && res.success && res.state == "20000") {
          callback && callback(null, res.data)
        } else if (res && res.state != '20000') {
          dsf.warn(res.message);
          callback && callback(res.message, null)
        } else {
          dsf.error("接口获取失败");
          callback && callback(true, null)
        }
      })
      .error(() => {
        dsf.error("接口获取失败");
        callback && callback(true, null)
      }).exec()
  }

}

