//初始化自动排座
function getBackendSortIframeUrl(seat, callback) {
  let autoSort = getAutoSortOption(seat);
  //如果dsf._seat_layout.js 根本没有配置autoSort直接返回
  if (!dsf.isDef(autoSort)) return callback();
  
  //如果autoSort.isOpenBackendSort 为false 直接返回
  if (!autoSort.isOpenBackendSort) {
    seat._isOpenBackendSort = false;
    return callback();
  }
  
  seat._isOpenBackendSort = true;
  let url = getBackendSortUrl(seat);
  if (!url) return callback();
  url = dsf.url.getAbsolutePath(url);
  let autoSortOption = getAutoSortOption(seat);
  if (!dsf.isDef(autoSortOption.params)) {
    seat._backendSortIframeUrl = url;
    return callback()
  }
  let params = autoSortOption.params();
  let queryStr = "";
  for (let k in params){
    queryStr += `${k}=${params[k]}&`
  }
  seat._backendSortIframeUrl = url+'?'+queryStr.substring(0, queryStr.length - 1);
  callback();
}


var treeFrame = {
  zTreeObj: null,
  seat: null,
  data: null,
  model: 'tree',
  init: function(seat) {
    let _this = this;
    this.seat = seat;
    let frame = getFrameOption(this.seat);
    let data = this.data;
    data = $.type(data) == "array" ? data : [data];
    var arr = [];
    let openLevel = frame.tree.openLevel;
    this.deepData(data, arr, 0, openLevel, null, this.seat);
    this.zTreeObj = $.fn.zTree.init($("#tree"), {
      view: {
        showIcon: frame.tree.showIcon
      },
      callback: {
        onExpand: function(evt, treeId, treeNode) {
          let id = treeNode.tId;
          let el = $("#" + id);
          let nodes = el.find(nodeSelector)
          attachDrag(_this.seat, nodes)
        }
      }
    }, arr);
    this.data = this.zTreeObj.getNodes();
  },
  deepData: function(data, arr, level, openLevel, parent) {
    let seat = this.seat;
    let _this = this;
    let frame = getFrameOption(this.seat);
    for (let i = 0; i < data.length; i++) {
      let d = data[i];
      let n = fn(d, parent);
      if (n) {
        arr.push(n);
      }
    }

    function fn(d, parent) {
      let obj = {};
      if (d) {
        obj.id = d[frame.data.id];
        obj.name = d[frame.data.name];
        if (frame.data.type) {
          obj.type = d[frame.data.type];
        }
        obj.attrs = d;
        if (dsf.isDef(openLevel)) {
          obj.open = level < openLevel ? true : false;
        }
        obj.pid = parent ? parent.id : "";
        let icon = getIcon(seat, obj);
        if (icon) {
          obj.icon = dsf.url.getAbsolutePath(icon);
        }
        obj.isHidden = seat._userInSeat[obj.id] ? true : false;
        if (frame.user(obj)) {
          setUsers(seat, obj);
        }
        let children;
        //你没看错就是=不是==
        if (children = d[frame.data.children]) {
          obj.children = [];
          _this.deepData(children, obj.children, level + 1, openLevel, obj);
        }

        return obj;
      }
    }
  },
  getNodeData(tid) {
    let id = tid.replace("_a", "");
    let node = this.zTreeObj.getNodeByTId(id);
    return node;
  },
  getUsersNodes(nodes) {
    let frame = getFrameOption(this.seat);
    nodes = dsf.type(nodes) == 'array' ? nodes : [nodes];
    let users = [];
    _.each(nodes, (node) => {
      fn(node);
    })

    function fn(node) {
      if (frame.user(node)) {
        if (!node.isHidden) {
          users.push(node);
        }
      } else {
        if (node.children && node.children.length) {
          _.each(node.children, (n) => {
            fn(n);
          })
        }
      }
    }
    return users;
  },
  diff() {
    let _this = this;
    let deleteArray = [],
      insertArray = [],
      updateArray = [];
    for (let i = 0; i < this.data.length; i++) {
      let n = this.data[i];
      fn.call(this, n);
    }
    _this.zTreeObj.hideNodes(deleteArray);
    _this.zTreeObj.showNodes(insertArray);

    function fn(n) {
      let checkChild = true;
      if (n) {
        if (this.seat._userInSeat[n.id]) {
          //如果已经入座则在树中排除掉该节点
          deleteArray.push(n);
          checkChild = false;
        } else {
          insertArray.push(n);
        }
      }
      if (checkChild && n.children) {
        for (let i = 0; i < n.children.length; i++) {
          fn.call(this, n.children[i]);
        }
      }
    }
  },
  clear: function(seatObj) {
    clearUser(seatObj);
    let nodes = this.zTreeObj.getNodes();
    for (let i = nodes.length - 1; i >= 0; i--) {
      this.zTreeObj.removeNode(nodes[i]);
    }

  }
}

var listFrame = {
  seat: null,
  data: null,
  userMap: {},
  model: 'list',
  init: function(seat) {
    let _this = this;
    this.seat = seat;
    let frame = getFrameOption(this.seat);
    let data = this.data;
    data = $.type(data) == "array" ? data : [data];
    var arr = [];
    this.deepData(data, arr, 0, null, this.seat);
    this.data = arr;
    // attachDrag(this.seat);
  },
  deepData: function(data, arr, level, parent) {
    let seat = this.seat;
    let _this = this;
    let frame = getFrameOption(this.seat);
    for (let i = 0; i < data.length; i++) {
      let d = data[i];
      let n = fn(d, parent);
    }

    function fn(d, parent) {
      let obj = {};
      if (d) {
        obj.id = d[frame.data.id];
        obj.name = d[frame.data.name];
        if (frame.data.type) {
          obj.type = d[frame.data.type];
        }
        obj.attrs = d;
        obj.pid = parent ? parent.id : "";
        let icon = getIcon(seat, obj);
        if (icon) {
          obj.icon = dsf.url.getAbsolutePath(icon);
        }
        obj.isHidden = seat._userInSeat[obj.id] ? true : false;
        if (frame.user(obj)) {
          setUsers(seat, obj);
          arr.push(obj)
          // _this.userMap[obj.id] = obj;
        } else {
          let children;
          if (children = d[frame.data.children]) {
            _this.deepData(children, arr, level + 1, obj);
          }
        }
        return obj;
      }
    }
  },
  getNodeData(id) {
    return this.seat._usersMap[id];
  },
  diff() {
    for (let k in this.seat._usersMap) {
      let u = this.seat._usersMap[k];
      let input = $("#check_" + u.id)
      if (this.seat._userInSeat[u.id]) {
        u.isHidden = true;
      } else {
        u.isHidden = false;
      }
      //更新列表是解除掉选中状态，避免下次拖动时收到干扰
      input.prop("checked", false);
    }
    this.seat._viewRender.renderAsync(() => {
      dsf.UI.renderDelay("checkbox");
    });
  },
  clear: function(seatObj) {
    clearUser(seatObj);
  }
}

//将用户存储到_users,_usersMap
function setUsers(seat, user) {
  seat._usersMap[user.id] = user;
  let index = _.findIndex(seat._users, (u) => {
    return u.id == user.id;
  });
  if (index < 0) {
    seat._users.push(user);
    user.sortNum = seat._users.length;
  }
}

function clearUser(seat) {
  seat._users = [];
  seat._usersMap = {};
}

//树控件附加拖拽
function attachDrag(seat, nodes) {
  if (!nodes) {
    if (seat._currentFrame.model == "tree") {
      let tree = $("#tree");
      nodes = tree.find(nodeSelector)
    } else {
      let list = $("#ulist");
      nodes = list.find(".ulist_item");
    }
  }
  if (nodes.length) {
    let dragNodes = [];
    nodes.each((i, el) => {
      let id = el.getAttribute("id");
      let node;
      if (seat._currentFrame.model == "tree") {
        id = id.replace("_a", "");
        node = seat._currentFrame.getNodeData(id);
      } else {
        node = seat._currentFrame.getNodeData(id);
      }
      if (isAllowDrag(seat, node)) {
        dragNodes.push($(el))
      }
    });
    if (dragNodes.length) {
      drag(seat, dragNodes);
    }
  }

}



let overEl = [];
//组织架构拖动
function drag(seat, el) {
  if (seat.readOnly) {
    return;
  }
  for (let i = 0; i < el.length; i++) {
    let e = el[i];
    e.draggable({
      "addClasses": false,
      "appendTo": ".ds_seat",
      "distance": 20,
      "revert": "invalid",
      "cursor": "move",
      "containment": "window",
      'cursorAt': { 'left': -5, 'top': -5 },
      "start": function(evt, ui) {
        let target = $(evt.currentTarget);
        let elId = target.attr("id");
        let nodeData;
        if (seat._currentFrame.model == "tree") {
          nodeData = treeFrame.getNodeData(elId);
          //如果是树结构架构，则过滤出所有下级子元素为用户的节点
          nodeData = seat._currentFrame.getUsersNodes(nodeData);
        } else {
          nodeData = getListChecked(seat, target);
        }
        nodeData = dsf.type(nodeData) == "array" ? nodeData : [nodeData];
        let users = _.map(nodeData, (n) => {
          return {
            id: n.id,
            name: n.name,
            attrs: n.attrs
          }
        });
        dragFrom = {
          'source': 'frame',
          'oldindex': null,
          'user': users || []
        }
      },
      "stop": function(event, ui) {
        dragFrom = null;
        overEl = [];
        $(".ds_seat_object.high").removeClass("high")
      },
      "drag": function(event, ui) {},
      "helper": function(evt) {
        let target = $(evt.currentTarget);
        let proxy;
        proxy = $("<div>");
        let text = getProxyText(seat, target);
        proxy.html(text);
        proxy.find("input").remove()
        proxy.addClass("ds_dragproxy").css({ 'z-index': 999 });
        return proxy;
      }
    });
  }

}

//座位表之间互拖
function drag2(seat) {
  if (seat.readOnly) {
    return;
  }
  let el = $(".ds_seat_panel").find(".user");
  el.each(function(i, el) {
    let e = $(el);
    let seatEl = e.parent();
    let sindex = seatEl.attr("seat-index");
    let s = seat._objectMap[sindex];
    if (s) {
      let isDisabled = !seat.isSeatUpdate(s);
      e.draggable({
        "addClasses": false,
        "appendTo": ".ds_seat",
        "revert": "invalid",
        "cursor": "move",
        'disabled': isDisabled,
        "containment": "window",
        "distance": 10,
        'cursorAt': { 'left': -5, 'top': -5 },
        "start": function(evt, ui) {
          let target = $(evt.currentTarget);
          let seatEl = target.parent();
          let sindex = seatEl.attr("seat-index");
          let user = seat._seat_user[sindex];
          user = seat._usersMap[user.userId];
          if (user) {
            dragFrom = {
              'oldindex': sindex,
              'source': 'seat',
              'user': $.extend({}, {
                id: user.id,
                name: user.name,
                attrs: user.attrs
              })
            }
          }
        },
        "stop": function(event, ui) {
          dragFrom = null;
          overEl = [];
          $(".ds_seat_object.high").removeClass("high")
        },
        "drag": function(event, ui) {},
        "helper": function(evt) {
          let target = $(evt.currentTarget);
          //获取座位编号
          let seatEl = target.parent();
          let sindex = seatEl.attr("seat-index");
          //获取座位上的用户
          let user = seat._seat_user[sindex];
          let userName = user.userName || "";
          let proxy = $("<div class='ds_dragproxy' style='z-index:999'>" + userName + "</div>");
          return proxy;
        }
      });
    }
  });

}

//拖放到座位
function drop(seat, el) {
  el.droppable({
    accept: function(a) {
      let index = this.getAttribute("seat-index");
      if (dsf.isUnDef(index) && index !== "") {
        return false;
      }
      let s = seat._objectMap[index];
      
      if (dragFrom) {
        let user = dragFrom.user;
        if (user) {
          let frame = seat.getFrameOption();
          user = dsf.type(user) === "array"? user[0]: user;
          if (frame.drop && frame.drop.allow) {
            return frame.drop.allow(user, s);
          }
          if (s && seat.isSeatUpdate(s) && (s.state != _STATUS.DISABLED && s.state != _STATUS.LOOK)) {
            return true;
          }
          return false;
        }
      }
      return false;
    },
    tolerance: "pointer",
    greedy: true,
    addClasses: false,
    out: function(event, ui) {
      _.remove(overEl, function(e) {
        return e == event.target;
      });
      // overEl=null;
      $(".ds_seat_object.high").removeClass("high")
      overEl[0] && $(overEl[0]).addClass("high");
    },
    over: function(event, ui) {
      overEl.push(event.target);
      $(".ds_seat_object.high").removeClass("high")
      $(overEl[0]).addClass("high");
    },
    drop: function(event, ui) {
      let seatEl = this;
      if (!seatEl.classList.contains("high")) {
        return
      }
      let user = dragFrom.user;
      if (user) {
        let num = seatEl.getAttribute("seat-index");
        user = dsf.type(user) == "array" ? user : [user];
        if (dragFrom.source == "frame") {
          addToSeatBatch(seat, user, num);
        } else {
          let data = [];
          //如果来自于座位间互相拖拽
          let user1 = seat._seat_user[num];
          let oi = dragFrom.oldindex;
          //如果座位号，用户没有发生变化则不做任何操作
          if (oi == num && user[0].userId == user1.userId) {
            return;
          }
          let r = getBatchSeat(seat, user, num);
          if (r && r.hasUserSeats && r.hasUserSeats.length) {
            dsf.layer.openHTMLView(
              '<div style="padding:10px">\
                               位置上已经存在其他人员,您希望如何处理？\
                            </div>', {
                id: "seatConfirm",
                area: ['450px', '200px'],
                btn: ['交换', '覆盖', '插入', '取消'],
                yes: function(index) {
                  seat.addToSeat(oi, user1);
                  data.push(getSaveData(seat, oi));
                  //将用户放到目标座位上
                  seat.addToSeat(num, user[0]);
                  data.push(getSaveData(seat, num));
                  dsf.layer.close(index)
                  seat.updateView();
                },
                btn2: function(index) {
                  seat.addToSeat(oi, null);
                  data.push(getSaveData(seat, oi));
                  coverageUserInSeat(seat, user, num, r, data);
                  dsf.layer.close(index)
                  seat.updateView();
                },
                btn3: function(index) {
                  seat.addToSeat(oi, null);
                  data.push(getSaveData(seat, oi));
                  insertUserInSeat(seat, user, num, r, data);
                  dsf.layer.close(index);
                  seat.updateView();
                }
              }
            );
          } else {
            seat.addToSeat(oi, null);
            data.push(getSaveData(seat, oi));
            coverageUserInSeat(seat, user, num, r, data);
            seat.updateView();
          }
        }
      }
    }
  });
}


function getProxyText(seat, target) {
  let text = ""
  if (seat._currentFrame.model == "tree") {
    let id = target.attr("id")
    let nodeData = seat._currentFrame.getNodeData(id);
    text = nodeData.name;
  } else {
    let nodeData = getListChecked(seat, target);
    if (nodeData.length > 3) {
      text = _.map(nodeData, "name").slice(0, 3).join("、") + "...";
    } else {
      text = _.map(nodeData, "name").join("、");
    }
  }
  return text;
}
//获取列表式拖动时多选情况下数据
function getListChecked(seat, target) {
  let result = [];
  let inputs = $("input[name='ulist']:checked");
  if (inputs.length > 0) {
    inputs.each((i, el) => {
      let inp = $(el);
      let id = inp.parent().attr("id");
      result.push(seat._currentFrame.getNodeData(id));
    });
  } else {
    let elId = target.attr("id")
    result.push(seat._currentFrame.getNodeData(elId));
  }
  return result;
}